// Lee el payload real de Meta ($json.body) y decide si el evento es procesable.
const body = $json.body || {};
const value = body.entry?.[0]?.changes?.[0]?.value || {};
const msg = value.messages?.[0];

// Payloads de estado (sent/delivered/read) u otros eventos sin mensaje: descartar
if (!msg) {
  return [{ json: { procesable: false, motivo: 'payload_sin_mensaje (status u otro evento)' } }];
}

const wamid = msg.id || '';
// Normalizacion de telefono: solo digitos, con codigo de pais, sin '+'
const telefono = String(msg.from || '').replace(/\D/g, '');
const tipo = msg.type || 'desconocido';
let mensaje = '';
let procesable = true;
let motivo = '';

if (tipo === 'text') {
  mensaje = (msg.text?.body || '').trim();
  if (!mensaje) { procesable = false; motivo = 'texto_vacio'; }
} else if (['audio','image','video','document','sticker','location','contacts'].includes(tipo)) {
  // Multimedia: la IA respondera pidiendo texto (no intentamos transcribir en el MVP)
  mensaje = '[Instruccion del sistema: el cliente envio un mensaje de tipo "' + tipo + '" que no puedes ver. Pidele amablemente que lo escriba en texto.]';
  motivo = 'multimedia_no_soportado';
} else {
  procesable = false; motivo = 'tipo_no_soportado: ' + tipo;
}

if (!wamid || !telefono) { procesable = false; motivo = 'faltan_wamid_o_telefono'; }

return [{ json: {
  procesable, motivo, wamid, telefono, tipo, mensaje,
  numero_bot: value.metadata?.phone_number_id || '',
  timestamp: $now.toISO()
} }];

// Parsea y VALIDA la respuesta del modelo. El total y la confirmacion
// se deciden en codigo, nunca a ciegas por el modelo.
const raw = $input.first().json;
const msgData = $('Validar y Extraer Mensaje').first().json;

let r = null;
let errorParseo = '';
try {
  const rawText = raw.choices?.[0]?.message?.content ?? '';
  const clean = rawText.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/, '').trim();
  r = JSON.parse(clean);
} catch (e) { errorParseo = e.message; }

if (!r || typeof r !== 'object' || typeof r.respuesta !== 'string') {
  const prev = $('Estado · Leer conversación').first()?.json || {};
  let pedidoPrev = []; try { pedidoPrev = JSON.parse(prev.pedido_actual || '[]'); } catch (e) {}
  r = {
    respuesta: 'Perdona, tuve un pequeno problema tecnico 😅 ¿Puedes repetirme eso?',
    nuevo_estado: prev.estado_conversacion || 'INICIO',
    pedido_actualizado: pedidoPrev,
    datos_cliente: { nombre: prev.nombre_cliente || '', fecha_retiro: prev.fecha_retiro || '', hora_retiro: prev.hora_retiro || '' },
    pedido_confirmado: false, total_pedido: 0, accion_interna: 'ninguna',
    nota_interna: 'ERROR parseo respuesta IA: ' + (errorParseo || 'estructura invalida')
  };
}

// ── Sanitizar ──
const pedido = (Array.isArray(r.pedido_actualizado) ? r.pedido_actualizado : [])
  .filter(p => p && p.producto)
  .map(p => ({ producto: String(p.producto), precio: Number(p.precio) || 0 }));
r.datos_cliente = r.datos_cliente || {};
const nombre = String(r.datos_cliente.nombre || '').trim();
const fechaRetiro = String(r.datos_cliente.fecha_retiro || '').trim();
const horaRetiro = String(r.datos_cliente.hora_retiro || '').trim();
r.accion_interna = ['ninguna', 'escalar_humano'].includes(r.accion_interna) ? r.accion_interna : 'ninguna';
const total = pedido.reduce((a, p) => a + p.precio, 0);

// ── Validaciones de negocio antes de aceptar una confirmacion ──
let confirmado = r.pedido_confirmado === true;
let motivo = '';
if (confirmado) {
  const reFecha = /^\d{4}-\d{2}-\d{2}$/;
  const reHora = /^([01]?\d|2[0-3]):[0-5]\d$/;
  if (!nombre) motivo = 'me falta tu nombre';
  else if (pedido.length === 0) motivo = 'no tengo productos anotados en el pedido';
  else if (!reFecha.test(fechaRetiro)) motivo = 'me falta la fecha de retiro';
  else if (!reHora.test(horaRetiro)) motivo = 'me falta la hora de retiro';
  else {
    const [hh, mm] = horaRetiro.split(':').map(Number);
    const minutos = hh * 60 + mm;
    const ahoraMin = $now.hour * 60 + $now.minute;
    const hoy = $now.toFormat('yyyy-MM-dd');
    const abre = 9 * 60, cierra = 21 * 60 + 30;
    if (fechaRetiro < hoy) motivo = 'esa fecha ya paso';
    else if (fechaRetiro === hoy && minutos <= ahoraMin) motivo = 'esa hora ya paso hoy';
    else if (minutos < abre || minutos > cierra) motivo = 'atendemos de 09:00 a 21:30';
    else {
      const esTortaEncargo = pedido.some(p => /torta|hojarasca|panqueque|merengue/i.test(p.producto) && p.precio >= 15000);
      if (esTortaEncargo) {
        const dias = (Date.parse(fechaRetiro) - Date.parse(hoy)) / 86400000;
        const diffMin = dias * 1440 + (minutos - ahoraMin);
        if (diffMin < 24 * 60) motivo = 'las tortas de encargo necesitan minimo 24 horas de anticipacion';
      }
    }
  }
  if (motivo) {
    confirmado = false;
    r.respuesta = 'Casi listo 😊 Solo un detalle antes de confirmar: ' + motivo + '. ¿Me lo confirmas?';
    r.nuevo_estado = 'DATOS_CLIENTE';
    r.nota_interna = ((r.nota_interna || '') + ' | Confirmacion bloqueada por validacion: ' + motivo).trim();
  }
}

// ── Historial ──
const historial = $('IA · Preparar contexto').first().json.historial_con_cliente || [];
historial.push({ rol: 'bot', texto: r.respuesta, ts: new Date().toISOString() });
const historialFinal = historial.length > 40 ? historial.slice(-40) : historial;

return [{ json: {
  ...r,
  pedido_actualizado: pedido,
  total_pedido: total,
  pedido_confirmado: confirmado,
  datos_cliente: { nombre, fecha_retiro: fechaRetiro, hora_retiro: horaRetiro },
  telefono: msgData.telefono,
  wamid: msgData.wamid,
  historial_para_sheets: JSON.stringify(historialFinal),
  pedido_para_sheets: JSON.stringify(pedido)
} }];

// Genera codigo unico de pedido y fechas ISO con offset real de Chile.
const r = $('IA · Parsear y validar').first().json;
const fecha = r.datos_cliente.fecha_retiro;
const hora = r.datos_cliente.hora_retiro.padStart(5, '0');

// Offset vigente de America/Santiago en esa fecha (maneja horario de verano)
function offsetSantiago(d) {
  const parts = new Intl.DateTimeFormat('en-US', { timeZone: 'America/Santiago', timeZoneName: 'longOffset' }).formatToParts(d);
  const tz = (parts.find(p => p.type === 'timeZoneName') || {}).value || '';
  const m = tz.match(/GMT([+-]\d{2}:\d{2})/);
  return m ? m[1] : '-04:00';
}
const off = offsetSantiago(new Date(fecha + 'T12:00:00Z'));
const [hh, mm] = hora.split(':').map(Number);
const endHora = String(Math.min(hh + 1, 23)).padStart(2, '0') + ':' + String(mm).padStart(2, '0');
const startIso = fecha + 'T' + hora + ':00' + off;
const endIso = fecha + 'T' + endHora + ':00' + off;

// Codigo unico y reproducible (derivado del wamid: reintentos generan el mismo)
const sufijo = (r.wamid || '').replace(/[^A-Za-z0-9]/g, '').slice(-6).toUpperCase() || String(Date.now()).slice(-6);
const codigo = 'LP-' + fecha.replace(/-/g, '') + '-' + sufijo;

const productosTxt = r.pedido_actualizado.map(p => '• ' + p.producto + ' — $' + p.precio.toLocaleString('es-CL')).join('\n');
const productosLinea = r.pedido_actualizado.map(p => p.producto + ' $' + p.precio).join(' | ');

return [{ json: { ...r, codigo_pedido: codigo, start_iso: startIso, end_iso: endIso, productos_txt: productosTxt, productos_linea: productosLinea } }];

// La llamada a OpenAI fallo (timeout, 4xx/5xx, red). Respuesta segura al cliente.
const msgData = $('Validar y Extraer Mensaje').first().json;
const err = $input.first().json;
return [{ json: {
  telefono: msgData.telefono,
  wamid: msgData.wamid,
  respuesta: 'Uy, tuve un problema tecnico 😅 Dame unos minutos y escribeme de nuevo, ¿ya?',
  workflow: 'la-pasteleria-bot-whatsapp-v2',
  nodo: 'IA · OpenAI Chat',
  tipo_error: 'openai_error',
  mensaje_error: String(err?.error?.message || err?.message || JSON.stringify(err || {})).slice(0, 300),
  fecha: $now.toISO()
} }];
